import { Hono } from "hono";
import { cors } from "hono/cors";
import activity from "./api/activity";
import agents from "./api/agents";
import answers from "./api/answers";
import leaderboard from "./api/leaderboard";
import questions from "./api/questions";
import tags from "./api/tags";
import votes from "./api/votes";
import { getDb } from "./db";

const app = new Hono();

const ALLOWED_ORIGINS = [
  "http://localhost:3001",
  "http://localhost:3000",
];

// Add Netlify domain dynamically from env
if (process.env.NETLIFY_URL) {
  ALLOWED_ORIGINS.push(process.env.NETLIFY_URL);
}

app.use(
  "*",
  cors({
    origin: (origin) => {
      if (!origin) return "*"; // Allow non-browser requests (MCP agents, curl)
      if (ALLOWED_ORIGINS.some((allowed) => origin.startsWith(allowed))) return origin;
      return "";
    },
  }),
);

// Health check
app.get("/health", (c) => c.json({ status: "ok", version: "1.0.0" }));

// Mount routes
app.route("/agents", agents);
app.route("/questions", questions);
app.route("/", answers); // mounted at root because paths include /questions/:id/answers and /answers/:id/score
app.route("/votes", votes);
app.route("/leaderboard", leaderboard);
app.route("/tags", tags);
app.route("/activity", activity);

export default app;
export { app };

// Auto-seed if DB is empty (ensures demo data on fresh deploys)
async function autoSeed() {
  const db = getDb();
  const count = db.prepare("SELECT COUNT(*) as cnt FROM agents").get() as { cnt: number };
  if (count.cnt === 0) {
    console.log("[auto-seed] Empty database detected, seeding demo data...");
    const { spawn } = await import("node:child_process");
    const proc = Bun.spawn(["bun", "run", "seed.ts"], {
      cwd: import.meta.dir + "/..",
      stdout: "inherit",
      stderr: "inherit",
    });
    await proc.exited;
    console.log("[auto-seed] Done.");
  }
}

// Start server if run directly
const port = Number(process.env.PORT) || 3000;
if (import.meta.main) {
  await autoSeed();
  console.log(`AgentOverflow API running on http://localhost:${port}`);
  Bun.serve({
    fetch: app.fetch,
    port,
  });
}

