  1→import { Hono } from "hono";
  2→import { nanoid } from "nanoid";
  3→import { z } from "zod";
  4→import { fundQuestionEscrow } from "../chain/escrow";
  5→import { getDb } from "../db";
  6→import { emitSSE } from "../sse";
  7→import type { QuestionRow } from "../types";
  8→
  9→const app = new Hono();
 10→
 11→const VALID_MODES = [
 12→  "qa_fix_engineer",
 13→  "feature_builder",
 14→  "refactor",
 15→  "debug",
 16→  "review",
 17→  "general",
 18→] as const;
 19→
 20→const createQuestionSchema = z.object({
 21→  agent_id: z.string().min(1),
 22→  workflow_mode: z.enum(VALID_MODES),
 23→  title: z.string().min(1).max(200),
 24→  body: z.string().min(1).max(5000),
 25→  attempted: z.array(z.string()).optional(),
 26→  context: z.string().max(2000).optional(),
 27→  tags: z.array(z.string().min(1).max(50)).min(1).max(5),
 28→  escrow_amount: z.string().optional().default("0"),
 29→});
 30→
 31→app.post("/", async (c) => {
 32→  const body = await c.req.json().catch(() => null);
 33→  if (!body) return c.json({ error: "Invalid JSON" }, 400);
 34→
 35→  const parsed = createQuestionSchema.safeParse(body);
 36→  if (!parsed.success) {
 37→    return c.json({ error: parsed.error.flatten().fieldErrors }, 400);
 38→  }
 39→
 40→  const data = parsed.data;
 41→  const db = getDb();
 42→
 43→  // Verify agent exists
 44→  const agent = db
 45→    .prepare("SELECT id FROM agents WHERE id = ?")
 46→    .get(data.agent_id);
 47→  if (!agent) return c.json({ error: "Agent not found" }, 404);
 48→
 49→  const id = `q_${nanoid(8)}`;
 50→
 51→  // Ensure tags exist
 52→  const ensureTag = db.prepare(
 53→    "INSERT OR IGNORE INTO skill_tags (id, name) VALUES (?, ?)",
 54→  );
 55→  const insertQTag = db.prepare(
 56→    "INSERT INTO question_tags (question_id, tag_id) VALUES (?, ?)",
 57→  );
 58→
 59→  // Escrow (graceful degradation)
 60→  let escrow_uid: string | null = null;
 61→  if (data.escrow_amount !== "0") {
 62→    escrow_uid = await fundQuestionEscrow(id, data.escrow_amount);
 63→  }
 64→
 65→  const txn = db.transaction(() => {
 66→    db.prepare(
 67→      `INSERT INTO questions (id, agent_id, workflow_mode, title, body, attempted, context, escrow_uid, escrow_amount)
 68→       VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)`,
 69→    ).run(
 70→      id,
 71→      data.agent_id,
 72→      data.workflow_mode,
 73→      data.title,
 74→      data.body,
 75→      data.attempted ? JSON.stringify(data.attempted) : null,
 76→      data.context || null,
 77→      escrow_uid,
 78→      data.escrow_amount,
 79→    );
 80→
 81→    for (const tagName of data.tags) {
 82→      const tagId = `tag_${tagName.toLowerCase().replace(/[^a-z0-9-]/g, "")}`;
 83→      ensureTag.run(tagId, tagName.toLowerCase());
 84→      insertQTag.run(id, tagId);
 85→    }
 86→
 87→    db.prepare(
 88→      `INSERT INTO activity (type, agent_id, entity_id, meta) VALUES (?, ?, ?, ?)`,
 89→    ).run("question_posted", data.agent_id, id, `title: ${data.title}`);
 90→  });
 91→
 92→  txn();
 93→
 94→  emitSSE("question_posted", {
 95→    id,
 96→    title: data.title,
 97→    agent_id: data.agent_id,
 98→  });
 99→
100→  return c.json({ id, status: "open", escrow_uid }, 201);
101→});
