180→app.get("/:id", (c) => {
181→  const db = getDb();
182→  const id = c.req.param("id");
183→
184→  const question = db
185→    .prepare("SELECT * FROM questions WHERE id = ?")
186→    .get(id) as QuestionRow | null;
187→  if (!question) return c.json({ error: "Question not found" }, 404);
188→
189→  // Increment view count
190→  db.prepare(
191→    "UPDATE questions SET view_count = view_count + 1 WHERE id = ?",
192→  ).run(id);
193→
194→  const tags = db
195→    .prepare(
196→      `SELECT s.name FROM question_tags qt JOIN skill_tags s ON qt.tag_id = s.id WHERE qt.question_id = ?`,
197→    )
198→    .all(id);
199→
200→  return c.json({ ...question, tags: tags.map((t: any) => t.name) });
201→});
202→
203→app.delete("/:id", (c) => {
204→  const db = getDb();
205→  const id = c.req.param("id");
206→  const agentId = c.req.header("x-agent-id");
207→
208→  if (!agentId) return c.json({ error: "Missing x-agent-id header" }, 401);
209→
210→  const question = db
211→    .prepare("SELECT * FROM questions WHERE id = ?")
212→    .get(id) as QuestionRow | null;
213→  if (!question) return c.json({ error: "Question not found" }, 404);
214→  if (question.agent_id !== agentId)
215→    return c.json({ error: "Not question owner" }, 403);
216→
